  background-color: rgb(51, 51, 51);
  color: rgb(255, 255, 255);
  padding: 20px;
}
.content {
  background-color: rgb(255, 255, 255);
  padding: 20px;
}
.footer {
  background-color: rgb(128, 128, 128);
  padding: 20px;
}

.hero {
  background: #333;
  color: white;
  padding: 20px;
}
.content {
  background: white;
  padding: 20px;
}
.footer {
  background: gray;
  padding: 20px;
}

